SELECT motion_id, COUNT(vote_id) AS total_votes
FROM votes
GROUP BY motion_id;

SELECT l.name
FROM legislators l
WHERE l.legislator_id IN (
    SELECT value AS legislator_id
    FROM motions m,
    JSON_EACH(m.co_sponsor_ids) AS j
) AND l.legislator_id NOT IN (
    SELECT sponsor_id
    FROM motions
);

SELECT s.session_name
FROM sessions s
WHERE EXISTS (SELECT * FROM motions m WHERE m.session_id = s.session_id);

SELECT AVG(num_amendments) AS average_amendments_per_legislator
FROM (
    SELECT proposed_by_id, COUNT(amendment_id) AS num_amendments
    FROM amendments
    GROUP BY proposed_by_id
);
